 ll[AtlasTeal!20] (1,2) – (4,2) – (2,5) – cycle;
 (1,2) – (4,2) – (2,5) – cycle;
 ll[AtlasTeal] (1,2) circle (3pt) node[below left] {$P$};
 ll[AtlasTeal] (4,2) circle (3pt) node[below right] {$Q$};
 ll[AtlasTeal] (2,5) circle (3pt) node[above left] {$R$};

 % Image triangle
 ll[AtlasWarm!20] (2,4) – (8,4) – (4,10) – cycle;
 (2,4) – (8,4) – (4,10) – cycle;
 ll[AtlasWarm] (2,4) circle (3pt) node[left] {$P'$};
 ll[AtlasWarm] (8,4) circle (3pt) node[right] {$Q'$};
 ll[AtlasWarm] (4,10) circle (3pt) node[above] {$R'$};

 % Origin
 ll[AtlasSage] (0,0) circle (4pt) node[below left] {$O$};

 % Rays from origin
 (0,0) – (2,4);
 (0,0) – (8,4);
 (0,0) – (4,10);
